  const hw = wallById[e.wallId];

  if (!hw || skipCat(hw)) continue;

  const elev = elevationMForLevel(hw.levelId, elementsById);

  root.add(makeDoorMesh(e, hw, elev, paint, selectedId));
}

for (const e of Object.values(elementsById)) {
